// ===========================================================================
// 1) 魂晶炸客 (s_bomber) — BOMB rusher.
//    AI 'charger': sits at a smouldering walk, then telegraphs (white blink +
//    spark ring from the engine's charger code) and DASHES into the player.
//    Low hp + very high CONTACT damage = it "detonates" on the player when it
//    connects. Red tint + the built-in charge flash read as a primed fuse.
//
//    NOTE: core Enemy has no def-level onDeath hook, and world.spawnExplosion /
//    dealAreaDamage only damage ENEMIES (never the player) — see world.js. So a
//    true death-blast that hurts the PLAYER is not expressible through the def
//    here; the working model is contact-detonation via the charger dash + heavy
//    touch damage, exactly the "keep it simple" fallback the brief allows.
// ===========================================================================
Enemies.register({
  id: 's_bomber', name: '魂晶炸客', sprite: 's_bomber', ai: 'charger', tier: 2, weight: 6,
  hp: 18, speed: 44, damage: 14, radius: 6, xp: 9, gold: 4, shard: 0.04,
  bloodColor: P.ember, tint: P.red, knockbackResist: 0,
  deathBlast: { r: 46, dmg: 34, color: P.ember },   // detonates on death — hurts the player too
  attack: { range: 170, cooldown: 1.2 },   // short fuse: charges often, dashes far
  desc: '渾身綁滿魂晶炸藥，點燃引信後不要命地撲上來自爆。',
});
defineAnim('s_bomber', 16, 14, 4, (p, f) => {
  const fuse = [0, 1, 2, 1][f % 4];         // sparking fuse flicker
  const by = 9;
  // little stubby legs
  p.rect(4, by + 3, 2, 2, P.ink2);
  p.rect(10, by + 3, 2, 2, P.ink2);
  // round bomb body (dark iron sphere)
  p.ellipse(8, by, 5, 4.6, P.ink2);
  p.ellipse(8, by - 0.4, 4, 3.6, P.gray1);
  p.ellipse(6.5, by - 1.6, 2, 1.4, P.gray3);     // metal highlight
  // riveted red danger band
  p.hline(3, 13, by + 1, P.redD);
  p.px(4, by + 1, P.red); p.px(8, by + 1, P.red); p.px(12, by + 1, P.red);
  // angry warning eyes
  p.px(6, by - 1, P.redL); p.px(10, by - 1, P.redL);
  p.px(6, by, P.white); p.px(10, by, P.white);
  // fuse collar + sparking fuse on top
  p.rect(7, by - 5, 2, 2, P.woodD);
  p.line(8, by - 5, 9 + fuse - 1, by - 8 - fuse, P.wood);
  p.px(9 + fuse - 1, by - 8 - fuse, P.emberL);
  if (fuse >= 1) { p.px(10 + fuse - 1, by - 9 - fuse, P.white); p.px(8 + fuse - 1, by - 9 - fuse, P.ember); }
  p.outline(P.ink);
}, { anchor: [8, 13], fps: 9 });

// ===========================================================================
// 2) 蝕魂水蛭 (s_sapper) — LEECH that "saps" the player on contact.
//    AI 'chase': slow, dogged, low damage but a sickly drain on touch. The
//    bilious green/purple tint + slow speed sell the energy-stealing flavour.
//
//    NOTE: there is no engine hook for stealing gold or applying a slow status
//    from an enemy definition (contact runs player.takeDamage only). The "sap"
//    is therefore thematic: persistent low-damage harassment that whittles you
//    down while the swarm distracts. Tint = toxic, blood = poison.
// ===========================================================================
Enemies.register({
  id: 's_sapper', name: '蝕魂水蛭', sprite: 's_sapper', ai: 'chase', tier: 2, weight: 7,
  hp: 40, speed: 30, damage: 8, radius: 6, xp: 8, gold: 1, shard: 0.03,
  bloodColor: P.poison, tint: P.poisonD, knockbackResist: 0.15,
  desc: '附吸在獵物身上不放的魂蛭，緩慢爬近啃食你的魂力與財帛。',
});
defineAnim('s_sapper', 16, 12, 4, (p, f) => {
  const undulate = [0, 1, 0, -1][f % 4];    // body ripple as it crawls
  const by = 7;
  // segmented slug body
  for (let i = 0; i < 5; i++) {
    const sx = 3 + i * 2.4;
    const sw = 3 - Math.abs(i - 2) * 0.4;
    const wob = Math.sin((i + f) * 0.9) * 0.8 + undulate * 0.4;
    p.ellipse(sx, by + wob, sw, 2.6, P.poisonD);
    p.ellipse(sx, by + wob - 0.4, sw - 0.8, 1.8, P.poison);
  }
  // sucker mouth (front)
  p.ellipse(13, by + undulate * 0.5, 2, 2, P.purpleD);
  p.ellipse(13, by + undulate * 0.5, 1, 1, P.blood);
  // pale clinging suckers underside
  p.px(5, by + 2, P.toxic); p.px(8, by + 2, P.toxic); p.px(11, by + 2, P.toxic);
  // glassy dorsal sheen
  p.px(6, by - 1, P.toxic); p.px(9, by - 1, P.toxic);
  // small dark eye-spots near the maw
  p.px(11, by - 1, P.ink); p.px(12, by - 2, P.ink);
  p.outline(P.ink);
}, { anchor: [8, 11], fps: 6 });

// ===========================================================================
// 3) 噬魂蚊 (s_gnat) — fast, erratic GNAT swarm flyer.
//    AI 'flyer': the engine adds a wobble to its approach, so it weaves and is
//    hard to hit. Very fast, almost no hp, low individual damage — annoyance in
//    numbers. High weight so they actually swarm.
// ===========================================================================
Enemies.register({
  id: 's_gnat', name: '噬魂蚊', sprite: 's_gnat', ai: 'flyer', tier: 1, weight: 10,
  hp: 6, speed: 82, damage: 5, radius: 4, xp: 2, gold: 1, shard: 0.01,
  bloodColor: P.greenD, tint: P.toxic, knockbackResist: 0,
  desc: '成雲成霧的噬魂蚊群，飛行刁鑽、難以瞄準，貼臉騷擾蠶食。',
});
defineAnim('s_gnat', 12, 10, 2, (p, f) => {
  const up = f % 2 === 0;
  const cy = 5;
  // tiny dark body
  p.ellipse(6, cy, 1.8, 2.2, P.greenD);
  p.ellipse(6, cy - 0.4, 1.1, 1.4, P.green);
  // glowing toxic eye
  p.px(6, cy - 1, P.toxic);
  // needle proboscis
  p.vline(cy + 2, cy + 3, 6, P.poisonD);
  // blurred buzzing wings (flicker between up/down)
  if (up) {
    p.line(5, cy - 1, 2, cy - 3, withAlpha(P.toxic, 0.85));
    p.line(7, cy - 1, 10, cy - 3, withAlpha(P.toxic, 0.85));
    p.px(2, cy - 3, P.greenL); p.px(10, cy - 3, P.greenL);
  } else {
    p.line(5, cy, 2, cy + 1, withAlpha(P.toxic, 0.85));
    p.line(7, cy, 10, cy + 1, withAlpha(P.toxic, 0.85));
    p.px(2, cy + 1, P.greenL); p.px(10, cy + 1, P.greenL);
  }
  p.outline(P.ink);
}, { anchor: [6, 7], fps: 12 });

// ===========================================================================
// 4) 噴酸蛞蝓 (s_spitter) — SHOOTER with an arcing acid volley.
//    AI 'shooter': holds range and lobs a 3-glob spread (burst+spread). Slow,
//    fat, heavy projectiles (low projSpeed + big radius + long life) so the
//    globs read as a lazy arcing volley raining toward the player.
// ===========================================================================
Enemies.register({
  id: 's_spitter', name: '噴酸蛞蝓', sprite: 's_spitter', ai: 'shooter', tier: 2, weight: 6,
  hp: 50, speed: 22, damage: 10, radius: 7, xp: 11, gold: 5, shard: 0.05,
  bloodColor: P.poison, tint: P.poison, knockbackResist: 0.2,
  attack: { range: 165, cooldown: 1.9, projSpeed: 78, projDamage: 11, projColor: P.poison, projSprite: 's_proj_acid', projRadius: 4, projLife: 3.2, burst: 3, spread: 0.30 },
  desc: '臃腫的腐酸蛞蝓，遠遠張口噴出三道弧線酸彈封鎖去路。',
});
defineAnim('s_spitter', 16, 13, 4, (p, f) => {
  const breathe = [0, 1, 1, 0][f % 4];      // body swells before a spit
  const by = 9;
  // broad slug foot
  p.hline(2, 13, by + 3, P.poisonD);
  p.hline(3, 12, by + 4, darken(P.poisonD, 0.25));
  // bloated body
  p.ellipse(8, by, 6, 3.4 + breathe * 0.4, P.poisonD);
  p.ellipse(8, by - 0.4, 5, 2.6 + breathe * 0.4, P.poison);
  p.ellipse(6.5, by - 1.6, 2.4, 1.2, P.toxic);    // wet sheen
  // acid sacs bulging on the back
  p.ellipse(5, by - 1, 1.4, 1.4, P.toxic); p.px(5, by - 1, P.greenL);
  p.ellipse(11, by - 1, 1.4, 1.4, P.toxic); p.px(11, by - 1, P.greenL);
  // eye stalks
  p.vline(by - 4, by - 1, 6, P.poisonD); p.vline(by - 4, by - 1, 10, P.poisonD);
  p.px(6, by - 5, P.greenL); p.px(10, by - 5, P.greenL);
  p.px(6, by - 5, P.white); p.px(10, by - 5, P.white);
  // drooling maw (opens when swelling)
  if (breathe >= 1) { p.ellipse(8, by + 1, 2, 1.4, P.blood); p.px(8, by + 2, P.toxic); }
  else { p.hline(7, 9, by + 1, P.blood); }
  p.outline(P.ink);
}, { anchor: [8, 12], fps: 6 });

// ===========================================================================
// 5) 詛咒巫眼 (s_hexer) — floating HEXER that kites and harasses with curse bolts.
//    AI 'shooter': keeps its distance and pelts you with fast single hex motes
//    (no burst) on a tight cooldown — constant disruptive chip pressure that
//    forces you to keep moving. Spectral, fragile, evasive.
// ===========================================================================
Enemies.register({
  id: 's_hexer', name: '詛咒巫眼', sprite: 's_hexer', ai: 'shooter', tier: 3, weight: 5,
  hp: 34, speed: 48, damage: 9, radius: 6, xp: 14, gold: 6, shard: 0.08,
  bloodColor: P.purple, tint: P.purpleL, knockbackResist: 0.1,
  attack: { range: 195, cooldown: 1.0, projSpeed: 150, projDamage: 9, projColor: P.purpleL, projSprite: 's_proj_hex', projRadius: 3, projLife: 2.6 },
  desc: '飄浮的獨眼咒物，遠遠睥睨並連珠射出詛咒彈，逼你不得停步。',
});
defineAnim('s_hexer', 16, 16, 3, (p, f) => {
  const yb = [0, -1, 0][f % 3];             // gentle hover bob
  const cx = 8, cy = 8 + yb;
  // writhing lower tendrils
  for (let i = 0; i < 4; i++) {
    const tx = 4 + i * 3;
    const sway = Math.sin((i + f) * 1.1) * 1.2;
    p.line(tx, cy + 2, tx + sway, cy + 5 + (i % 2), P.purpleD);
    p.px(tx + sway, cy + 5 + (i % 2), P.purple);
  }
  // floating orb head
  p.ellipse(cx, cy, 4.4, 4.4, P.purpleD);
  p.ellipse(cx, cy, 3.4, 3.4, P.purple);
  p.ellipse(cx - 1, cy - 1.4, 1.6, 1.2, P.purpleL);   // top sheen
  // big single sclera
  p.ellipse(cx, cy, 2.6, 2.6, P.bone);
  // iris + pupil (a baleful glare)
  p.ellipse(cx, cy, 1.5, 1.5, P.purpleD);
  p.px(cx, cy, P.ink);
  p.px(cx - 1, cy - 1, P.white);            // catch-light
  // crackling hex sparks orbiting the brow
  p.px(cx - 4 + yb, cy - 3, P.purpleL); p.px(cx + 4 - yb, cy - 3, P.manaL);
  p.outline(P.ink);
}, { anchor: [8, 13], fps: 5 });
